COPY package*.json ${1:./}
RUN npm ci
COPY ${2:.} ${3:./}

RUN groupadd -r ${1:appuser} && useradd -r -g ${1:appuser} -d /home/${1:appuser} -s /sbin/nologin ${1:appuser} \
    && mkdir -p /home/${1:appuser} && chown -R ${1:appuser}:${1:appuser} /home/${1:appuser}
USER ${1:appuser}

FROM ${1:node:20-alpine} AS builder
WORKDIR /app
COPY . .
RUN ${2:npm ci && npm run build}

FROM ${3:node:20-alpine}
WORKDIR /app
COPY --from=builder /app/${4:dist} ./${4:dist}
EXPOSE ${5:3000}
CMD ${6:["node", "dist/index.js"]}

# Copy dependency manifests first (changes less often)
COPY ${1:package.json} ${2:package-lock.json} ./
RUN ${3:npm ci}

# Copy source code (changes more often)
COPY . .
RUN ${4:npm run build}
